// DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useCallback, useRef, useMemo } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}

function useComponent(props: Props) {
  // Map weather condition to emoji icon
  const weatherEmoji = useCallback(() => {
    const condition = props.condition.toLowerCase();
    if (condition.includes('sunny') || condition.includes('clear')) return '☀️';
    if (condition.includes('cloudy') || condition.includes('overcast')) return '☁️';
    if (condition.includes('rainy') || condition.includes('rain')) return '🌧️';
    if (condition.includes('snow')) return '❄️';
    if (condition.includes('storm') || condition.includes('thunder')) return '⛈️';
    if (condition.includes('wind')) return '💨';
    if (condition.includes('fog') || condition.includes('mist')) return '🌫️';
    return '🌤️'; // Default partly cloudy
  }, [props.condition]);

  return {
    weatherEmoji: weatherEmoji(),
  };
}

export default function Component(props: Props) {
  const state = useComponent(props);

  return (
    <Container maxWidth="lg" padding={0}>{/* Container for the weather card */}
      <Card shadow="md" padding={24} radius="lg">
        <Stack gap={16}>
          {/* Header with city and basic info */}
          <Stack direction="horizontal" justify="between" align="center">
            <Stack gap={2}>
              <Heading level={2} color="var(--ggui-color-onSurface, #18181b)">{props.city}</Heading>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">{props.condition}</Text>
            </Stack>
            <Text size="3xl" weight="bold" color="var(--ggui-color-primary-600, #0284c7)">{state.weatherEmoji}</Text>
          </Stack>

          <Divider margin={8} />

          {/* Current Temperature (Large, Prominent) */}
          <Box textAlign="center" padding={16}>
            <Text size="4xl" weight="bold" color="var(--ggui-color-primary-600, #0284c7)" align="center">
              {props.temperature}°{props.unit}
            </Text>
          </Box>

          {/* Humidity and Wind Speed */}
           <Stack gap={16} direction="horizontal" justify="between" align="stretch">
             {/* Humidity Card */}
             <Card shadow="sm" padding={16} radius="md">
               <Stack gap={8} align="center">
                 <Icon name="droplets" size={24} color="var(--ggui-color-primary-500, #0ea5e9)" />
                 <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Humidity</Text>
                 <Text size="lg" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">{props.humidity}%</Text>
               </Stack>
             </Card>

             {/* Wind Speed Card */}
             <Card shadow="sm" padding={16} radius="md">
               <Stack gap={8} align="center">
                 <Icon name="wind" size={24} color="var(--ggui-color-primary-500, #0ea5e9)" />
                 <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Wind Speed</Text>
                 <Text size="lg" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">{props.windSpeed} km/h</Text>
               </Stack>
             </Card>
           </Stack>

          <Divider margin={8} />

           {/* 5-Day Forecast Strip */}
           <Stack gap={12}>
             <Stack direction="horizontal" gap={8} justify="start" align="center">
               {(props.forecast || []).map((day, index) => {
                 const dayName = day?.day || 'N/A';
                 const dayIcon = day?.icon || '🌤️';
                 const dayHigh = day?.high !== undefined ? day.high : '--';
                 const dayLow = day?.low !== undefined ? day.low : '--';
                 return (
                   <Box
                     key={index}
                     padding={12}
                     background="var(--ggui-color-surfaceVariant, #f4f4f5)"
                     borderRadius={8}
                     style={{ flex: '0 1 auto', minWidth: '80px' }}
                   >
                     <Stack gap={8} align="center">
                       <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)" align="center">{dayName}</Text>
                        <Text size="lg" weight="bold" color="var(--ggui-color-onSurface, #18181b)">{dayIcon}</Text>
                       <Text variant="caption" color="var(--ggui-color-onSurface, #18181b)" align="center">{dayHigh}°{props.unit}/{dayLow}°{props.unit}</Text>
                     </Stack>
                   </Box>
                 );
               })}
             </Stack>
           </Stack>
        </Stack>
      </Card>
    </Container>
  );
}

// DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';


// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };

function useComponent(props: Props) {
  // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit'); // Called with all collected answers as a structured object

  const [currentStep, setCurrentStep] = useState(1);
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfaction, setSatisfaction] = useState('');
  const [selectedFeatures, setSelectedFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState('');

  // Validation
  const nameError = currentStep >= 1 && !name.trim() ? 'Name is required' : '';
  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  const emailError = currentStep >= 1 && !email.trim() ? 'Email is required' : currentStep >= 1 && !emailRegex.test(email) ? 'Please enter a valid email' : '';
  const satisfactionError = currentStep >= 2 && !satisfaction ? 'Please select a satisfaction rating' : '';
  const featuresError = currentStep >= 3 && selectedFeatures.length === 0 ? 'Please select at least one feature' : '';

  const isStep1Valid = !nameError && !emailError;
  const isStep2Valid = !satisfactionError;
  const isStep3Valid = !featuresError;
  const isStep4Valid = true; // Comments are optional

  const handleNext = useCallback(() => {
    if (currentStep === 1 && !isStep1Valid) return;
    if (currentStep === 2 && !isStep2Valid) return;
    if (currentStep === 3 && !isStep3Valid) return;
    setCurrentStep(prev => Math.min(prev + 1, 5));
  }, [currentStep, isStep1Valid, isStep2Valid, isStep3Valid]);

  const handleBack = useCallback(() => {
    setCurrentStep(prev => Math.max(prev - 1, 1));
  }, []);

  const handleSubmit = useCallback(() => {
    submit({
      name: name.trim(),
      email: email.trim(),
      satisfaction: parseInt(satisfaction, 10),
      features: selectedFeatures,
      comments: comments.trim(),
    });
  }, [submit, name, email, satisfaction, selectedFeatures, comments]);

  const handleFeatureToggle = useCallback((feature: string) => {
    setSelectedFeatures(prev =>
      prev.includes(feature) ? prev.filter(f => f !== feature) : [...prev, feature]
    );
  }, []);

  return { submit, currentStep, setCurrentStep, name, setName, email, setEmail, satisfaction, setSatisfaction, selectedFeatures, handleFeatureToggle, comments, setComments, nameError, emailError, satisfactionError, featuresError, isStep1Valid, isStep2Valid, isStep3Valid, handleNext, handleBack, handleSubmit };
}

export default function Component(props: Props) {
  const state = useComponent(props);

  const {
    currentStep,
    name,
    setName,
    email,
    setEmail,
    satisfaction,
    setSatisfaction,
    selectedFeatures,
    handleFeatureToggle,
    comments,
    setComments,
    nameError,
    emailError,
    satisfactionError,
    featuresError,
    isStep1Valid,
    isStep2Valid,
    isStep3Valid,
    handleNext,
    handleBack,
    handleSubmit,
  } = state;

  const satisfactionOptions = props.satisfactionLabels.map((label, index) => ({
    value: (index + 1).toString(),
    label,
  }));

  return (
    <Container maxWidth="md" padding={32}>
      <Stack gap={24}>
        {/* Progress Bar */}
        <Box>
          <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)" style={{ marginBottom: 'var(--ggui-spacing-2, 8px)', display: 'block' }}>
            Step {currentStep} of 4
          </Text>
          <Progress value={currentStep} max={4} variant="default" size="md" />
        </Box>

        {/* Step 1: Name and Email */}
        {currentStep === 1 && (
          <Card shadow="md" padding={24} radius="lg">
            <Stack gap={16}>
              <Heading level={3}>Contact Information</Heading>
              <Input
                label="Full Name"
                placeholder="Enter your full name"
                value={name}
                onChange={setName}
                error={nameError}
                required
              />
              <Input
                label="Email Address"
                type="email"
                placeholder="you@example.com"
                value={email}
                onChange={setEmail}
                error={emailError}
                required
              />
            </Stack>
          </Card>
        )}

        {/* Step 2: Satisfaction Rating */}
        {currentStep === 2 && (
          <Card shadow="md" padding={24} radius="lg">
            <Stack gap={16}>
              <Heading level={3}>Satisfaction Rating</Heading>
              <RadioGroup
                label="How satisfied are you with our service?"
                value={satisfaction}
                onChange={setSatisfaction}
                options={satisfactionOptions}
                direction="vertical"
                error={satisfactionError}
              />
            </Stack>
          </Card>
        )}

        {/* Step 3: Feature Interests */}
        {currentStep === 3 && (
          <Card shadow="md" padding={24} radius="lg">
            <Stack gap={16}>
              <Heading level={3}>Feature Interests</Heading>
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">Which features interest you? (Select at least one)</Text>
              <Stack gap={12}>
                {props.featureOptions.map(feature => (
                  <Checkbox
                    key={feature}
                    label={feature}
                    checked={selectedFeatures.includes(feature)}
                    onChange={() => handleFeatureToggle(feature)}
                  />
                ))}
              </Stack>
              {featuresError && (
                <Text variant="caption" color="var(--ggui-color-error-500, #ef4444)">{featuresError}</Text>
              )}
            </Stack>
          </Card>
        )}

        {/* Step 4: Comments */}
        {currentStep === 4 && (
          <Card shadow="md" padding={24} radius="lg">
            <Stack gap={16}>
              <Heading level={3}>Additional Comments</Heading>
              <TextArea
                label="Comments"
                placeholder="Share any additional thoughts or feedback (optional)"
                value={comments}
                onChange={setComments}
                rows={6}
                maxLength={500}
                showCount
              />
            </Stack>
          </Card>
        )}

        {/* Step 5: Review */}
        {currentStep === 5 && (
          <Card shadow="md" padding={24} radius="lg">
            <Stack gap={16}>
              <Heading level={3}>Review Your Answers</Heading>
              <Stack gap={12}>
                <Box>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Name</Text>
                  <Text variant="body">{name}</Text>
                </Box>
                <Divider orientation="horizontal" margin={8} />
                <Box>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Email</Text>
                  <Text variant="body">{email}</Text>
                </Box>
                <Divider orientation="horizontal" margin={8} />
                <Box>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Satisfaction Rating</Text>
                  <Text variant="body">{props.satisfactionLabels[parseInt(satisfaction, 10) - 1]}</Text>
                </Box>
                <Divider orientation="horizontal" margin={8} />
                <Box>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Selected Features</Text>
                  <Stack gap={8} direction="horizontal" wrap>
                    {selectedFeatures.map(feature => (
                      <Badge key={feature} variant="primary" size="sm">{feature}</Badge>
                    ))}
                  </Stack>
                </Box>
                <Divider orientation="horizontal" margin={8} />
                <Box>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Comments</Text>
                  <Text variant="body">{comments || '(None provided)'}</Text>
                </Box>
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Navigation Buttons */}
        <Stack direction="horizontal" gap={12} justify="between">
          <Button
            variant="ghost"
            onClick={handleBack}
            disabled={currentStep === 1}
          >
            Back
          </Button>
          {currentStep < 5 ? (
            <Button
              variant="primary"
              onClick={handleNext}
              disabled={
                (currentStep === 1 && !isStep1Valid) ||
                (currentStep === 2 && !isStep2Valid) ||
                (currentStep === 3 && !isStep3Valid)
              }
            >
              Next
            </Button>
          ) : (
            <Button
              variant="primary"
              onClick={handleSubmit}
            >
              Submit
            </Button>
          )}
        </Stack>
      </Stack>
    </Container>
  );
}

// DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column: string } };

// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };

function useComponent(props: Props) {
  // Actions — fire-and-forget to agent
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate'); // Called when a task is moved, edited, or created. Payload: { action, taskId, data }

  // Streams — real-time from agent (.latest, .all)
  const taskChanged = useStream<StreamTaskChanged>('taskChanged'); // A task was moved, edited, or created by another user — update it in the board

  // Local task state (merges props + stream updates)
  const [tasks, setTasks] = useState(() => props.tasks || []);
  const [newTaskForm, setNewTaskForm] = useState<{ visible: boolean; columnId: string; title: string; priority: 'low' | 'medium' | 'high' }>({
    visible: false,
    columnId: props.columns?.[0]?.id || 'todo',
    title: '',
    priority: 'medium',
  });
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [editingTitle, setEditingTitle] = useState('');

  // Update tasks from props and stream events
  React.useEffect(() => {
    setTasks(props.tasks || []);
  }, [props.tasks]);

  React.useEffect(() => {
    if (taskChanged.latest?.task) {
      const updated = taskChanged.latest.task;
      setTasks((prev) => {
        const idx = prev.findIndex((t) => t.id === updated.id);
        if (idx >= 0) {
          const newTasks = [...prev];
          if (taskChanged.latest?.action === 'delete') {
            newTasks.splice(idx, 1);
          } else {
            newTasks[idx] = { ...newTasks[idx], ...updated };
          }
          return newTasks;
        } else if (taskChanged.latest?.action === 'create') {
          return [...prev, updated];
        }
        return prev;
      });
    }
  }, [taskChanged.latest]);

  // Handlers
  const handleMoveTask = useCallback((taskId: string, newColumn: string) => {
    setTasks((prev) =>
      prev.map((t) => (t.id === taskId ? { ...t, column: newColumn } : t))
    );
    taskUpdate({ action: 'move', taskId, data: { column: newColumn } });
  }, [taskUpdate]);

  const handleAddTask = useCallback(() => {
    if (!newTaskForm.title.trim()) return;
    const taskId = `task-${Date.now()}`;
    const newTask = {
      id: taskId,
      title: newTaskForm.title,
      priority: newTaskForm.priority,
      column: newTaskForm.columnId,
      assignee: '',
      dueDate: '',
    };
    setTasks((prev) => [...prev, newTask]);
    taskUpdate({ action: 'create', taskId, data: { column: newTaskForm.columnId } });
    setNewTaskForm({ ...newTaskForm, title: '', priority: 'medium' });
  }, [newTaskForm, taskUpdate]);

  const handleEditTask = useCallback((taskId: string, newTitle: string) => {
    if (!newTitle.trim()) return;
    setTasks((prev) =>
      prev.map((t) => (t.id === taskId ? { ...t, title: newTitle } : t))
    );
    taskUpdate({ action: 'edit', taskId, data: { column: tasks.find((t) => t.id === taskId)?.column || '' } });
    setEditingTaskId(null);
    setEditingTitle('');
  }, [tasks, taskUpdate]);

  const tasksByColumn = useCallback(() => {
    return (props.columns || []).map((col) => ({
      ...col,
      tasks: tasks.filter((t) => t.column === col.id),
    }));
  }, [tasks, props.columns]);

  const completedCount = tasks.filter((t) => t.column === 'done').length;
  const totalCount = tasks.length;

  return { taskUpdate, taskChanged, tasks, newTaskForm, setNewTaskForm, editingTaskId, setEditingTaskId, editingTitle, setEditingTitle, handleMoveTask, handleAddTask, handleEditTask, tasksByColumn, completedCount, totalCount };
}

export default function Component(props: Props) {
  const state = useComponent(props);

  const priorityColors: { [key: string]: 'primary' | 'warning' | 'error' } = {
    low: 'primary',
    medium: 'warning',
    high: 'error',
  };

  return (
    <Container maxWidth='3xl'>
      <Stack gap={16} direction='vertical'>
        {/* Summary Bar */}
        <Box background='var(--ggui-color-surfaceVariant, #f4f4f5)' padding={16} borderRadius={8}>
          <Stack direction='horizontal' justify='between' align='center'>
            <div>
              <Text variant='label'>Tasks Progress</Text>
              <Text variant='body'>{state.completedCount} of {state.totalCount} completed</Text>
            </div>
            <Progress value={state.totalCount > 0 ? (state.completedCount / state.totalCount) * 100 : 0} max={100} size='md' />
          </Stack>
        </Box>

        {/* Columns Grid */}
        <Stack gap={16} wrap direction='horizontal'>
          {state.tasksByColumn().map((colGroup) => (
            <Box key={colGroup.id} style={{ flex: '1 1 300px', minWidth: '300px' }}>
              <Card shadow='sm' padding={16} radius='lg'>
                {/* Column Header */}
                <Stack gap={12} direction='vertical'>
                  <Stack direction='horizontal' justify='between' align='center'>
                    <Stack direction='horizontal' align='center' gap={8}>
                      <Heading level={4}>{colGroup.name}</Heading>
                      <Badge variant='default'>{colGroup.tasks?.length || 0}</Badge>
                    </Stack>
                  </Stack>
                  <Divider orientation='horizontal' margin={8} />

                  {/* Task Cards */}
                  <Stack direction='vertical' gap={12}>
                    {(colGroup.tasks || []).map((task) => (
                      <Card key={task.id} shadow='sm' padding={12} border={true} radius='md' as={Hoverable} hoverStyle={{ boxShadow: 'var(--ggui-shape-shadow-md)' }} style={{ cursor: 'pointer' }}>
                        <Stack direction='vertical' gap={8}>
                          {/* Task Title */}
                          {state.editingTaskId === task.id ? (
                            <Stack direction='horizontal' gap={8} align='center'>
                              <Input label='Edit task' value={state.editingTitle} onChange={(val) => state.setEditingTitle(val)} size='sm' />
                              <Button size='sm' variant='primary' onClick={() => state.handleEditTask(task.id || '', state.editingTitle)}>
                                Save
                              </Button>
                              <Button size='sm' variant='ghost' onClick={() => { state.setEditingTaskId(null); state.setEditingTitle(''); }}>
                                Cancel
                              </Button>
                            </Stack>
                          ) : (
                            <Stack direction='horizontal' justify='between' align='start' gap={8}>
                              <Text variant='body' weight='semibold' as={Clickable} onClick={() => { state.setEditingTaskId(task.id || ''); state.setEditingTitle(task.title || ''); }}>
                                {task.title || '(Untitled)'}
                              </Text>
                              <Button size='xs' variant='ghost' onClick={() => { state.setEditingTaskId(task.id || ''); state.setEditingTitle(task.title || ''); }}>
                                ✎
                              </Button>
                            </Stack>
                          )}

                          {/* Priority Badge */}
                          {task.priority && <Badge variant={priorityColors[task.priority]}>{task.priority}</Badge>}

                          {/* Assignee & Due Date */}
                          <Stack direction='horizontal' gap={8} align='center'>
                            {task.assignee && <Avatar name={task.assignee} size='sm' shape='circle' />}
                            {task.dueDate && <Text variant='caption' color='var(--ggui-color-onSurfaceVariant, #52525b)'>{task.dueDate}</Text>}
                          </Stack>

                          {/* Move Button */}
                          {props.columns && props.columns.length > 1 && (
                            <Dropdown
                              trigger={<Button size='xs' variant='outline'>Move</Button>}
                              options={props.columns
                                .filter((c) => c.id !== task.column)
                                .map((c) => ({ value: c.id || '', label: c.name || '' }))}
                              value={task.column || ''}
                              onChange={(newCol) => state.handleMoveTask(task.id || '', newCol)}
                              placement='bottom-end'
                            />
                          )}
                        </Stack>
                      </Card>
                    ))}
                  </Stack>

                  {/* Add Task Form or Button */}
                  <Divider orientation='horizontal' margin={8} />
                  {state.newTaskForm.visible && state.newTaskForm.columnId === colGroup.id ? (
                    <Stack direction='vertical' gap={8}>
                      <Input
                        label='Task title'
                        placeholder='Enter task title...'
                        value={state.newTaskForm.title}
                        onChange={(val) => state.setNewTaskForm({ ...state.newTaskForm, title: val })}
                        size='sm'
                      />
                      <Select
                        label='Priority'
                        value={state.newTaskForm.priority}
                        onChange={(val) => state.setNewTaskForm({ ...state.newTaskForm, priority: val as 'low' | 'medium' | 'high' })}
                        options={[
                          { value: 'low', label: 'Low' },
                          { value: 'medium', label: 'Medium' },
                          { value: 'high', label: 'High' },
                        ]}
                        size='sm'
                      />
                      <Stack direction='horizontal' gap={8}>
                        <Button size='sm' variant='primary' fullWidth onClick={state.handleAddTask}>
                          Create
