                        <Button
                          size='sm'
                          variant='ghost'
                          fullWidth
                          onClick={() => state.setNewTaskForm({ ...state.newTaskForm, visible: false, title: '' })}
                        >
                          Cancel
                        </Button>
                      </Stack>
                    </Stack>
                  ) : (
                    <Button
                      size='sm'
                      variant='outline'
                      fullWidth
                      onClick={() => state.setNewTaskForm({ ...state.newTaskForm, visible: true, columnId: colGroup.id || '' })}
                    >
                      + Add Task
                    </Button>
                  )}
                </Stack>
              </Card>
            </Box>
          ))}
