import React, { useState, useCallback, useRef, useMemo } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  elements: Array<{ atomicNumber?: number; symbol?: string; name?: string; atomicWeight?: number; category?: string; row?: number; col?: number }>; // Full periodic table element data
}

function useComponent(props: Props) {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<typeof props.elements[0] | null>(null);

  // Filter elements based on search query (name or symbol)
  const filteredElements = useMemo(() => {
    if (!searchQuery.trim()) {
      return props.elements;
    }
    const query = searchQuery.toLowerCase();
    return props.elements.filter((el) => {
      const symbol = (el.symbol || '').toLowerCase();
      const name = (el.name || '').toLowerCase();
      return symbol.includes(query) || name.includes(query);
    });
  }, [searchQuery, props.elements]);

  // Get unique categories with color mapping
  const categories = useMemo(() => {
    const categorySet = new Set(props.elements.map((el) => el.category).filter(Boolean));
    const categoryColors: Record<string, string> = {
      'alkali metal': 'var(--ggui-color-primary-600, #0284c7)',
      'alkaline earth metal': 'var(--ggui-color-primary-400, #38bdf8)',
      'transition metal': 'var(--ggui-color-success-500, #22c55e)',
      'post-transition metal': 'var(--ggui-color-warning-500, #f59e0b)',
      'metalloid': 'var(--ggui-color-warning-400, #fbbf24)',
      'nonmetal': 'var(--ggui-color-error-500, #ef4444)',
      'halogen': 'var(--ggui-color-error-400, #f87171)',
      'noble gas': 'var(--ggui-color-info-500, #06b6d4)',
      'lanthanide': 'var(--ggui-color-primary-300, #7dd3fc)',
      'actinide': 'var(--ggui-color-primary-200, #bae6fd)',
    };
    return Array.from(categorySet).map((category) => ({
      name: category || 'Unknown',
      color: categoryColors[category || 'unknown'] || 'var(--ggui-color-surfaceVariant, #f4f4f5)',
    }));
  }, [props.elements]);

  const getCategoryColor = useCallback((category?: string) => {
    const categoryColor = categories.find((c) => c.name === category);
    return categoryColor?.color || 'var(--ggui-color-surfaceVariant, #f4f4f5)';
  }, [categories]);

  return {
    searchQuery,
    setSearchQuery,
    selectedElement,
    setSelectedElement,
    filteredElements,
    categories,
    getCategoryColor,
  };
}
}

export default function Component(props: Props) {
  const state = useComponent(props);

  return (
    <Container maxWidth="3xl" padding={24}>
      <Stack gap={24}>
        {/* Title */}
        <Stack gap={8}>
          <Heading level={1}>Periodic Table of Elements</Heading>
