          </Text>
        </Stack>

        {/* Search Bar */}
        <Box>
          <SearchField
            value={state.searchQuery}
            onChange={state.setSearchQuery}
            onSearch={state.setSearchQuery}
            placeholder="Search by name or symbol..."
            size="md"
          />
        </Box>

        {/* Legend */}
        <Card shadow="sm" padding={16}>
          <Stack gap={12}>
            <Text variant="label">Legend</Text>
            <Row gap={12} wrap>
              {state.categories.map((category) => (
                <Row key={category.name} gap={6} align="center">
                  <Box
                    background={category.color}
                    borderRadius={4}
                    padding={8}
                    style={{ minWidth: '12px', minHeight: '12px' }}
                  />
                  <Text variant="caption">{category.name}</Text>
                </Row>
              ))}
            </Row>
          </Stack>
        </Card>

        {/* Periodic Table Grid */}
        <Box
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(18, 1fr)',
            gap: 'var(--ggui-spacing-2, 8px)',
            padding: 'var(--ggui-spacing-4, 16px)',
            background: 'var(--ggui-color-surface, #fafafa)',
            borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
            border: '1px solid var(--ggui-color-outline, #d4d4d8)',
          }}
        >
          {state.filteredElements.map((element) => {
            const gridRow = (element.row || 1) + 1; // +1 for header spacing if needed
            const gridCol = element.col || 1;
            const isSelected = state.selectedElement?.atomicNumber === element.atomicNumber;
            const bgColor = state.getCategoryColor(element.category);

            return (
              <Card
                key={element.atomicNumber || Math.random()}
                as={Clickable}
                onClick={() => state.setSelectedElement(element)}
                padding={8}
                shadow="sm"
                border={isSelected}
                radius="md"
                style={{
                  gridRow,
                  gridColumn: gridCol,
                  background: bgColor,
                  cursor: 'pointer',
                  opacity: isSelected ? 1 : 0.85,
                  transform: isSelected ? 'scale(1.05)' : 'scale(1)',
                  transition: 'all 200ms ease-in-out',
                  minHeight: '60px',
                  display: 'flex',
                  flexDirection: 'column',
                  justifyContent: 'center',
                  alignItems: 'center',
                  position: 'relative',
                  border: isSelected ? '2px solid var(--ggui-color-primary-600, #0284c7)' : '1px solid rgba(0,0,0,0.1)',
                }}
              >
                {/* Atomic number (small, top-left) */}
                <Text
                  variant="caption"
                  style={{
                    position: 'absolute',
                    top: 'var(--ggui-spacing-1, 4px)',
                    left: 'var(--ggui-spacing-1, 4px)',
                    fontSize: 'var(--ggui-font-size-xs, 12px)',
                  }}
                >
                  {element.atomicNumber}
                </Text>

                {/* Symbol (large, centered) */}
                <Text
                  variant="label"
                  align="center"
                  size="lg"
                  weight="bold"
                  style={{
                    fontSize: 'var(--ggui-font-size-xl, 20px)',
                    fontWeight: 'var(--ggui-font-weight-bold, 700)',
                  }}
                >
                  {element.symbol}
                </Text>
              </Card>
            );
          })}
        </Box>

        {/* Detail Panel */}
        {state.selectedElement && (
          <Card shadow="md" padding={20}>
            <Stack gap={16}>
              <Stack gap={4}>
                <Heading level={3}>{state.selectedElement.name}</Heading>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  {state.selectedElement.category}
                </Text>
              </Stack>

              <Divider margin={8} />

              <Row gap={24}>
                <Stack gap={4}>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    Symbol
                  </Text>
                  <Text variant="bodyLarge" weight="semibold">
                    {state.selectedElement.symbol}
                  </Text>
                </Stack>
                <Stack gap={4}>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    Atomic Number
                  </Text>
                  <Text variant="bodyLarge" weight="semibold">
                    {state.selectedElement.atomicNumber}
                  </Text>
                </Stack>
                <Stack gap={4}>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    Atomic Weight
                  </Text>
                  <Text variant="bodyLarge" weight="semibold">
                    {state.selectedElement.atomicWeight?.toFixed(3) || 'N/A'}
                  </Text>
                </Stack>
              </Row>

              <Box
                background={state.getCategoryColor(state.selectedElement.category)}
                borderRadius={6}
                padding={12}
                style={{
                  textAlign: 'center',
                }}
              >
                <Text variant="label">{state.selectedElement.category}</Text>
              </Box>

              <Button
                variant="outline"
                onClick={() => state.setSelectedElement(null)}
                fullWidth
              >
                Close
              </Button>
            </Stack>
          </Card>
        )}
      </Stack>
    </Container>
  );
}

