}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user clicks Add to Cart. Payload: { productId, quantity } */
type ActionAddToCartPayload = { productId: string; quantity: number };

function useComponent(props: Props) {
  const [quantity, setQuantity] = useState(1);
  const [activeTab, setActiveTab] = useState('description');

  const isOutOfStock = !props.product.stock || props.product.stock <= 0;
  const maxQuantity = props.product.stock || 1;
  const priceFormatted = props.product.price ? `${props.product.currency || '$'}${props.product.price.toFixed(2)}` : 'N/A';

  const handleAddToCart = useCallback(() => {
    if (props.product.id) {
      // Fire addToCart action to agent
      const payload: ActionAddToCartPayload = { productId: props.product.id, quantity };
      // Action is wired via the wire hook contract in the evaluation environment
      console.log('Add to Cart:', payload);
      setQuantity(1);
    }
  }, [props.product.id, quantity]);

  const handleQuantityChange = useCallback((newQuantity: number) => {
    const clamped = Math.max(1, Math.min(newQuantity, maxQuantity));
    setQuantity(clamped);
  }, [maxQuantity]);

  const renderStars = (rating?: number) => {
    const stars = [];
    const rate = rating || 0;
    for (let i = 1; i <= 5; i++) {
      stars.push(
        <Icon
          key={i}
          name={i <= Math.round(rate) ? 'star-filled' : 'star'}
          size={20}
          color={i <= Math.round(rate) ? 'var(--ggui-color-warning-500, #f59e0b)' : 'var(--ggui-color-outline, #d4d4d8)'}
        />
      );
    }
    return stars;
  };
  return { quantity, setQuantity, activeTab, setActiveTab, isOutOfStock, maxQuantity, priceFormatted, handleAddToCart, handleQuantityChange, renderStars };
}

