              key: 'description',
              label: 'Description',
              content: (
                <Box padding="var(--ggui-spacing-4, 16px) 0">
                  <Text variant="body">{props.product.description || 'No description available.'}</Text>
                </Box>
              ),
            },
            {
              key: 'specifications',
              label: 'Specifications',
              content: (
                <Box padding="var(--ggui-spacing-4, 16px) 0">
                  {Array.isArray(props.product.specifications) && props.product.specifications.length > 0 ? (
                    <Table
                      columns={[
                        { key: 'key', header: 'Property', width: '40%' },
                        { key: 'value', header: 'Value', width: '60%' },
