                        value: typeof spec === 'object' && spec !== null ? spec.value || '' : String(spec),
                      }))}
                      striped={false}
                      hoverable={true}
                      compact={true}
                    />
                  ) : (
                    <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      No specifications available.
                    </Text>
                  )}
                </Box>
              ),
            },
            {
              key: 'reviews',
              label: 'Reviews',
              content: (
                <Box padding="var(--ggui-spacing-4, 16px) 0">
                  {Array.isArray(props.product.reviews) && props.product.reviews.length > 0 ? (
                    <Stack gap="var(--ggui-spacing-4, 16px)" direction="vertical">
                      {props.product.reviews.map((review: any, idx: number) => (
                        <Card key={idx} padding="var(--ggui-spacing-4, 16px)" shadow="none" border={true}>
                          <Stack gap="var(--ggui-spacing-2, 8px)" direction="vertical">
                            <Row gap="var(--ggui-spacing-2, 8px)" align="center">
                              <Text variant="label" weight="semibold">
                                {review.author || 'Anonymous'}
                              </Text>
                              <Row gap="var(--ggui-spacing-1, 4px)">
                                {Array.from({ length: 5 }).map((_, i) => (
                                  <Icon
                                    key={i}
                    name={i < (review.rating || 0) ? 'star-filled' : 'star'}
                                    size={16}
                                    color={
                                      i < (review.rating || 0)
                                        ? 'var(--ggui-color-warning-500, #f59e0b)'
                                        : 'var(--ggui-color-outline, #d4d4d8)'
                                    }
                                  />
                                ))}
                              </Row>
                            </Row>
                            <Text variant="body">{review.text || review.comment || 'No text'}</Text>
                            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                              {review.date ? new Date(review.date).toLocaleDateString() : 'Date unknown'}
                            </Text>
                          </Stack>
                        </Card>
                      ))}
                    </Stack>
                  ) : (
                    <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      No reviews yet.
                    </Text>
                  )}
                </Box>
              ),
            },
          ]}
        />

        <Divider />

        {/* Bottom section: Quantity selector and Add to Cart */}
        <Stack gap="var(--ggui-spacing-4, 16px)" direction="horizontal" align="center">
          <Stack gap="var(--ggui-spacing-2, 8px)" direction="horizontal" align="center">
            <Text variant="label">Quantity:</Text>
            <Button
              variant="outline"
              size="sm"
              onClick={() => state.handleQuantityChange(state.quantity - 1)}
              disabled={state.quantity <= 1}
            >
              −
            </Button>
            <Box
              padding="var(--ggui-spacing-1, 4px) var(--ggui-spacing-2, 8px)"
              style={{ minWidth: '40px', textAlign: 'center', border: '1px solid var(--ggui-color-outline, #d4d4d8)', borderRadius: 'var(--ggui-shape-radius-md, 8px)' }}
            >
              <Text variant="body" align="center">
                {state.quantity}
              </Text>
            </Box>
            <Button
              variant="outline"
              size="sm"
              onClick={() => state.handleQuantityChange(state.quantity + 1)}
              disabled={state.quantity >= state.maxQuantity}
            >
              +
            </Button>
          </Stack>
          <Button
            variant="primary"
            size="md"
            onClick={state.handleAddToCart}
            disabled={state.isOutOfStock}
            fullWidth={false}
          >
            Add to Cart
          </Button>
        </Stack>
      </Stack>
    </Container>
  );
}

