  const state = useComponent(props);

  return (
    <Container maxWidth="lg" padding={16}>
      <Card shadow="md" radius="lg" padding={0}>
        <Stack gap={0} direction="vertical">
          {/* Header */}
          <Box
            paddingX={16}
            paddingY={12}
            background="var(--ggui-color-container, #ede9fe)"
            style={{
