              overflowY: 'auto',
            }}
          >
            <Stack gap={8} direction="vertical">
              {state.allMessages.map((msg, index) => {
                const isCurrentUser = msg.sender === props.currentUser;
                const nextMsg = state.allMessages[index + 1];
                const sameSender = nextMsg?.sender === msg.sender;

                return (
                  <div key={`msg-${index}`}>
                    {/* Show sender name only for first message from sender */}
                    {!sameSender || index === 0 || state.allMessages[index - 1]?.sender !== msg.sender ? (
                      <Text
                        variant="caption"
                        color="var(--ggui-color-onSurfaceVariant, #52525b)"
                        style={{ marginBottom: 'var(--ggui-spacing-1, 4px)' }}
                      >
                        {msg.sender || 'Unknown'}
                      </Text>
                    ) : null}
                    <Box
                      paddingX={12}
                      paddingY={8}
                      background={
                        isCurrentUser
                          ? 'var(--ggui-color-primary-600, #0284c7)'
                          : 'var(--ggui-color-surfaceVariant, #f4f4f5)'
                      }
                      borderRadius={8}
                      style={{
                        marginLeft: isCurrentUser ? 'auto' : '0',
                        marginRight: isCurrentUser ? '0' : 'auto',
                        maxWidth: '70%',
                      }}
                    >
                      <Text
                        variant="body"
                        color={isCurrentUser ? '#ffffff' : 'var(--ggui-color-onSurface, #18181b)'}
                        style={{ wordWrap: 'break-word' }}
                      >
                        {msg.text || ''}
                      </Text>
                      {msg.timestamp ? (
                        <Text
                          variant="caption"
                          color={isCurrentUser ? 'rgba(255,255,255,0.7)' : 'var(--ggui-color-onSurfaceVariant, #52525b)'}
                          style={{ marginTop: 'var(--ggui-spacing-1, 4px)', fontSize: 'var(--ggui-font-size-xs, 12px)' }}
                        >
                          {new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                        </Text>
                      ) : null}
                    </Box>
                  </div>
                );
              })}

              {/* Typing Indicator */}
              {state.typingUser ? (
                <Box
                  paddingX={12}
                  paddingY={8}
                  background="var(--ggui-color-surfaceVariant, #f4f4f5)"
                  borderRadius={8}
                  style={{ marginRight: 'auto' }}
                >
                  <Text
                    variant="caption"
                    color="var(--ggui-color-onSurfaceVariant, #52525b)"
                    style={{ fontStyle: 'italic' }}
                  >
                    {state.typingUser} is typing
                    <span style={{ animation: 'pulse 1.5s cubic-bezier(0.4, 0, 0.6, 1) infinite' }}>.</span>
                  </Text>
                  <style>{`
                    @keyframes pulse {
                      0%, 100% { opacity: 1; }
                      50% { opacity: 0.5; }
                    }
                  `}</style>
                </Box>
              ) : null}

              {/* Scroll anchor */}
              <div ref={state.messagesEndRef} />
            </Stack>
          </Box>

          <Divider orientation="horizontal" margin={0} color="var(--ggui-color-outline, #d4d4d8)" />

          {/* Input Area */}
          <Box paddingX={16} paddingY={12} background="var(--ggui-color-surface, #ffffff)">
            <Stack direction="horizontal" gap={8} align="end">
              <Box style={{ flex: 1 }}>
                <TextArea
                  label="Message"
                  placeholder="Type your message..."
                  value={state.inputText}
                  onChange={state.setInputText}
                  rows={3}
                  style={{ width: '100%' }}
                />
              </Box>
              <Button
                variant="primary"
                size="md"
                onClick={state.handleSendMessage}
                disabled={!state.inputText.trim()}
              >
                Send
              </Button>
            </Stack>
          </Box>
        </Stack>
      </Card>
    </Container>
  );
}

