// DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { MotionKeyframes, useMotion } from '@ggui-ai/design/primitives';

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>; // Array of stocks with symbol, name, price, change, changePercent
}

// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: Updated price data for one or more stocks */
type StreamPriceUpdate = { symbol?: string; price?: number; change?: number; changePercent?: number };

/** Stream event: Market open/closed status update */
type StreamMarketStatus = { status?: 'open' | 'closed' | 'pre-market' | 'after-hours'; timestamp?: string };

function useComponent(props: Props) {
  // State for managing stocks and flash animation
  const [stocks, setStocks] = useState(props.stocks || []);
  const [lastUpdatedTime, setLastUpdatedTime] = useState(new Date());
  const [flashingSymbols, setFlashingSymbols] = useState<Set<string>>(new Set());

  // Listen for real-time price updates via ggui:agent-data events
  // Listen for real-time price updates via ggui:agent-data events
  React.useEffect(() => {
    const handleAgentData = (event: Event) => {
      try {
        const customEvent = event as CustomEvent;
        const data = customEvent.detail;

        // Handle priceUpdate stream events
        if (data?.type === 'priceUpdate' && data?.payload) {
          const update = data.payload as StreamPriceUpdate;

          // Validate required symbol field
          if (!update.symbol) {
            console.warn('Invalid priceUpdate: missing symbol field', update);
            return;
          }

          setStocks(prevStocks =>
            prevStocks.map(stock =>
              stock.symbol === update.symbol
                ? {
                    ...stock,
                    price: update.price ?? stock.price,
                    change: update.change ?? stock.change,
                    changePercent: update.changePercent ?? stock.changePercent,
                  }
                : stock
            )
          );
          // Trigger flash animation
          setFlashingSymbols(prev => new Set([...prev, update.symbol]));
          setLastUpdatedTime(new Date());
          // Remove flash after 500ms
          const timer = setTimeout(() => {
            setFlashingSymbols(prev => {
              const next = new Set(prev);
              next.delete(update.symbol);
              return next;
            });
          }, 500);
        }
      } catch (error) {
        console.error('Error processing stream event:', error);
      }
    };

    window.addEventListener('ggui:agent-data', handleAgentData);
    return () => window.removeEventListener('ggui:agent-data', handleAgentData);
  }, []);

  const formatPrice = useCallback((price?: number) => {
    if (price === undefined) return 'N/A';
    return `$${price.toFixed(2)}`;
  }, []);

  const getChangeColor = useCallback((changePercent?: number) => {
    if (changePercent === undefined) return 'var(--ggui-color-onSurface, #18181b)';
    return changePercent >= 0
      ? 'var(--ggui-color-success-600, #16a34a)'
      : 'var(--ggui-color-error-600, #dc2626)';
  }, []);

  const getChangeBorderColor = useCallback((changePercent?: number) => {
    if (changePercent === undefined) return 'var(--ggui-color-outline, #d4d4d8)';
    return changePercent >= 0
      ? 'var(--ggui-color-success-200, #bbf7d0)'
      : 'var(--ggui-color-error-200, #fecaca)';
  }, []);

  const getArrowIcon = useCallback((changePercent?: number) => {
    if (changePercent === undefined) return '';
    return changePercent >= 0 ? '▲' : '▼';
  }, []);

  return { stocks, lastUpdatedTime, flashingSymbols, formatPrice, getChangeColor, getChangeBorderColor, getArrowIcon };
}

export default function Component(props: Props) {
  const state = useComponent(props);
  const { motionEnabled } = useMotion();

  return (
    <>
      <MotionKeyframes />
      <style>{`
        @keyframes flash-highlight {
          0% { background-color: var(--ggui-color-primary-100, #e0f2fe); }
          100% { background-color: var(--ggui-color-surface, #ffffff); }
        }
      `}</style>
      <Container maxWidth="lg" padding="var(--ggui-spacing-6, 24px)">
        <Stack gap="var(--ggui-spacing-6, 24px)">
          {/* Header with title and timestamp */}
          <Stack direction="horizontal" justify="between" align="center">
            <Heading level={1}>Market Watch</Heading>
            <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)" align="center">
              <Icon name="clock" size={16} color="var(--ggui-color-onSurfaceVariant, #52525b)" />
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Last Updated: {state.lastUpdatedTime.toLocaleTimeString()}
              </Text>
            </Stack>
          </Stack>

          {/* Responsive grid of stock cards */}
          <div className="stock-grid" style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(3, 1fr)',
            gap: 'var(--ggui-spacing-4, 16px)',
          }}>
            {/* Desktop: 3 columns, Tablet: 2 columns, Mobile: 1 column */}
            <style>{`
              @media (max-width: 1024px) {
                .stock-grid {
                  grid-template-columns: repeat(2, 1fr);
                }
              }
              @media (max-width: 640px) {
                .stock-grid {
                  grid-template-columns: 1fr;
                }
              }
            `}</style>
            {state.stocks.length === 0 ? (
              <Box style={{ gridColumn: '1 / -1', padding: 'var(--ggui-spacing-6, 24px)', textAlign: 'center' }}>
                <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">No stocks available</Text>
              </Box>
            ) : (
              state.stocks.map((stock, index) => {
                const isFlashing = state.flashingSymbols.has(stock.symbol || '');
                return (
                  <Card
                    key={stock.symbol || index}
                    padding="var(--ggui-spacing-4, 16px)"
                    shadow="md"
                    radius="lg"
                    style={{
                      borderWidth: '2px',
                      borderStyle: 'solid',
                      borderColor: state.getChangeBorderColor(stock.changePercent),
                      transition: 'background-color 500ms ease-in-out',
                      backgroundColor: isFlashing
                        ? 'var(--ggui-color-primary-100, #e0f2fe)'
                        : 'var(--ggui-color-surface, #ffffff)',
                      animation: isFlashing ? 'flash-highlight 500ms ease-in-out' : 'none',
                    }}
                  >
                    <Stack gap="var(--ggui-spacing-3, 12px)">
                      {/* Ticker symbol (large, bold) */}
                      <Text
                        variant="overline"
                        size="2xl"
                        weight="bold"
                        color="var(--ggui-color-onSurface, #18181b)"
                      >
                        {stock.symbol || 'N/A'}
                      </Text>

                      {/* Company name */}
                      <Text
                        variant="bodySmall"
                        color="var(--ggui-color-onSurfaceVariant, #52525b)"
                      >
                        {stock.name || 'Unknown'}
                      </Text>

                      <Divider margin="var(--ggui-spacing-2, 8px)" />

                      {/* Current price */}
                      <Stack direction="horizontal" justify="between" align="center">
                        <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                          Price
                        </Text>
                        <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                          {state.formatPrice(stock.price)}
                        </Text>
                      </Stack>

                      {/* Change amount and percentage with color coding */}
                      <Stack direction="horizontal" justify="between" align="center">
                        <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                          Change
                        </Text>
                        <Stack direction="horizontal" gap="var(--ggui-spacing-1, 4px)" align="center">
                          <Text
                            variant="body"
                            weight="semibold"
                            color={state.getChangeColor(stock.changePercent)}
                          >
                            {stock.change !== undefined
                              ? (stock.change >= 0 ? '+' : '') + stock.change.toFixed(2)
                              : 'N/A'}
                          </Text>
                          <Text
                            variant="body"
                            weight="semibold"
                            color={state.getChangeColor(stock.changePercent)}
                          >
                            {stock.changePercent !== undefined
                              ? `(${stock.changePercent >= 0 ? '+' : ''}${stock.changePercent.toFixed(2)}%)`
                              : '(N/A)'}
                          </Text>
                          <Text
                            variant="body"
                            weight="semibold"
                            color={state.getChangeColor(stock.changePercent)}
                            size="lg"
                          >
                            {state.getArrowIcon(stock.changePercent)}
                          </Text>
                        </Stack>
                      </Stack>
                    </Stack>
                  </Card>
                );
              })
            )}
          </div>
        </Stack>
      </Container>
      </Container>
  );
}

// DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useCallback } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, Select, Toggle, Badge, Progress } from '@ggui-ai/design/primitives';
import { Clickable } from '@ggui-ai/design/interact';



// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  initialProfile: { name?: string; email?: string; avatar?: string; role?: string; emailNotifications?: boolean; theme?: string }; // Pre-filled profile data for editing (all fields optional)
  avatarOptions: string[]; // Available avatar emojis to choose from
  roleOptions: string[]; // Available role options for the dropdown
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all profile data when user completes onboarding */
type ActionCompletePayload = { name: string; email: string; avatar: string; role: string; emailNotifications: boolean; theme: string };

function useComponent(props: Props) {
  // Actions — fire-and-forget to agent
  const complete = useAction<ActionCompletePayload>('complete'); // Called with all profile data when user completes onboarding

  // State management
  const [currentStep, setCurrentStep] = useState(1);
  const [name, setName] = useState(props.initialProfile.name || '');
  const [email, setEmail] = useState(props.initialProfile.email || '');
  const [avatar, setAvatar] = useState(props.initialProfile.avatar || '');
  const [role, setRole] = useState(props.initialProfile.role || '');
  const [emailNotifications, setEmailNotifications] = useState(props.initialProfile.emailNotifications ?? true);
  const [theme, setTheme] = useState(props.initialProfile.theme || 'light');

  // Validation
  const isValidEmail = (value: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value);
  const nameError = name.trim() === '' ? 'Name is required' : '';
  const emailError = email.trim() === '' ? 'Email is required' : !isValidEmail(email) ? 'Invalid email format' : '';
  const step1Valid = !nameError && !emailError && avatar !== '';
  const step2Valid = role !== '';

  // Navigation handlers
  const handleNext = useCallback(() => {
    if (currentStep === 1 && step1Valid) {
      setCurrentStep(2);
    } else if (currentStep === 2 && step2Valid) {
      setCurrentStep(3);
    }
  }, [currentStep, step1Valid, step2Valid]);

  const handleBack = useCallback(() => {
    setCurrentStep(Math.max(1, currentStep - 1));
  }, [currentStep]);

  const handleComplete = useCallback(() => {
    complete({
      name: name.trim(),
      email: email.trim(),
      avatar,
      role,
      emailNotifications,
      theme
    });
  }, [name, email, avatar, role, emailNotifications, theme, complete]);

  return {
    currentStep,
    setCurrentStep,
    name,
    setName,
    email,
    setEmail,
    avatar,
    setAvatar,
    role,
    setRole,
    emailNotifications,
    setEmailNotifications,
    theme,
    setTheme,
    nameError,
    emailError,
    step1Valid,
    step2Valid,
    handleNext,
    handleBack,
    handleComplete
  };
}

export default function Component(props: Props) {
  const state = useComponent(props);

  return (
    <Container maxWidth='md' padding={24}> {/* Main container */}
      <Stack gap={24} align='center'>
        {/* Step Indicator */}
