            </Badge>
            <Text variant='label' color='var(--ggui-color-onSurfaceVariant, #52525b)'>
              {state.currentStep === 1 && 'Profile Setup'}
              {state.currentStep === 2 && 'Preferences'}
              {state.currentStep === 3 && 'Review & Confirm'}
            </Text>
          </Stack>
          <Progress value={state.currentStep * 33.33} max={100} variant='default' size='md' />
        </Stack>

        {/* Step 1: Profile Setup */}
        {state.currentStep === 1 && (
          <Card shadow='md' padding={24} radius='lg' style={{ width: '100%' }}>
            <Stack gap={20} align='stretch'>
              <Heading level={3}>Profile Setup</Heading>
              <Stack gap={16} align='stretch'>
                {/* Name Input */}
                <Input
                  label='Full Name'
                  value={state.name}
                  onChange={state.setName}
                  placeholder='Enter your full name'
                  required
                  error={state.nameError}
                />

                {/* Email Input */}
                <Input
                  label='Email Address'
                  type='email'
                  value={state.email}
                  onChange={state.setEmail}
                  placeholder='you@example.com'
                  required
                  error={state.emailError}
                />

                {/* Avatar Selection */}
                <Stack gap={8} align='stretch'>
                  <Text variant='label' color='var(--ggui-color-onSurfaceVariant, #52525b)'>
                    Choose Avatar <Text as='span' color='var(--ggui-color-error-500, #dc2626)'>*</Text>
                  </Text>
                  <Row gap={12} align='center' justify='start' wrap>
                    {props.avatarOptions.map((ava) => (
                      <Box
                        key={ava}
                        as={Clickable}
                        onClick={() => state.setAvatar(ava)}
                        style={{
                          width: '56px',
                          height: '56px',
                          borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
                          border: state.avatar === ava ? '3px solid var(--ggui-color-primary-600, #0284c7)' : '2px solid var(--ggui-color-outline, #d4d4d8)',
                          display: 'flex',
                          alignItems: 'center',
                          justifyContent: 'center',
                          fontSize: '32px',
                          cursor: 'pointer',
                          transition: 'all 200ms ease-in-out',
                          background: state.avatar === ava ? 'var(--ggui-color-primary-50, #f0f9ff)' : 'var(--ggui-color-surface, #fafafa)'
                        }}
                        hoverStyle={{ transform: 'scale(1.05)' }}
                      >
                        {ava}
                      </Box>
                    ))}
                  </Row>
                </Stack>
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Step 2: Preferences */}
        {state.currentStep === 2 && (
          <Card shadow='md' padding={24} radius='lg' style={{ width: '100%' }}>
            <Stack gap={20} align='stretch'>
              <Heading level={3}>Preferences</Heading>
              <Stack gap={20} align='stretch'>
                {/* Role Selection */}
                <Select
                  label='Role'
                  value={state.role}
                  onChange={state.setRole}
                  options={props.roleOptions.map((r) => ({ value: r, label: r }))}
                  placeholder='Select your role'
                  required
                />

                {/* Email Notifications Toggle */}
                <Toggle
                  label='Email Notifications'
                  checked={state.emailNotifications}
                  onChange={state.setEmailNotifications}
                  size='md'
                />

                {/* Theme Preference Toggle */}
                <Toggle
                  label={`Theme: ${state.theme === 'light' ? 'Light' : 'Dark'}`}
                  checked={state.theme === 'dark'}
                  onChange={(checked) => state.setTheme(checked ? 'dark' : 'light')}
                  size='md'
                />
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Step 3: Review & Confirm */}
        {state.currentStep === 3 && (
          <Card shadow='md' padding={24} radius='lg' style={{ width: '100%' }}>
            <Stack gap={20} align='stretch'>
              <Heading level={3}>Review & Confirm</Heading>
              <Stack gap={16} align='stretch'>
                {/* Summary Section */}
                <Box padding={16} background='var(--ggui-color-primary-50, #f0f9ff)' borderRadius='var(--ggui-shape-radius-md, 8px)'>
                  <Stack gap={12} align='stretch'>
                    <Text variant='label' color='var(--ggui-color-primary-700, #0369a1)'>Profile Information</Text>
                    <Stack gap={8} align='stretch'>
                      <Row gap={12} align='center' justify='between'>
                        <Text variant='bodySmall' color='var(--ggui-color-onSurfaceVariant, #52525b)'>Name:</Text>
                        <Text variant='body' weight='semibold'>{state.name}</Text>
                      </Row>
                      <Row gap={12} align='center' justify='between'>
                        <Text variant='bodySmall' color='var(--ggui-color-onSurfaceVariant, #52525b)'>Email:</Text>
                        <Text variant='body' weight='semibold'>{state.email}</Text>
                      </Row>
                      <Row gap={12} align='center' justify='between'>
                        <Text variant='bodySmall' color='var(--ggui-color-onSurfaceVariant, #52525b)'>Avatar:</Text>
                        <Text variant='body' style={{ fontSize: '24px' }}>{state.avatar}</Text>
                      </Row>
                    </Stack>
                  </Stack>
                </Box>

                <Divider />

                {/* Preferences Summary */}
                <Box padding={16} background='var(--ggui-color-primary-50, #f0f9ff)' borderRadius='var(--ggui-shape-radius-md, 8px)'>
                  <Stack gap={12} align='stretch'>
                    <Text variant='label' color='var(--ggui-color-primary-700, #0369a1)'>Preferences</Text>
                    <Stack gap={8} align='stretch'>
                      <Row gap={12} align='center' justify='between'>
                        <Text variant='bodySmall' color='var(--ggui-color-onSurfaceVariant, #52525b)'>Role:</Text>
                        <Badge variant='primary' size='sm'>{state.role}</Badge>
                      </Row>
                      <Row gap={12} align='center' justify='between'>
                        <Text variant='bodySmall' color='var(--ggui-color-onSurfaceVariant, #52525b)'>Email Notifications:</Text>
                        <Badge variant={state.emailNotifications ? 'success' : 'default'} size='sm'>
                          {state.emailNotifications ? 'Enabled' : 'Disabled'}
                        </Badge>
                      </Row>
                      <Row gap={12} align='center' justify='between'>
                        <Text variant='bodySmall' color='var(--ggui-color-onSurfaceVariant, #52525b)'>Theme:</Text>
                        <Badge variant='primary' size='sm'>{state.theme === 'light' ? 'Light' : 'Dark'}</Badge>
                      </Row>
                    </Stack>
                  </Stack>
                </Box>
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Navigation Buttons */}
        <Row gap={12} align='center' justify='center' style={{ width: '100%' }}>
          {state.currentStep > 1 && (
            <Button variant='outline' size='md' onClick={state.handleBack}>
              Go Back
            </Button>
          )}
          <Spacer size='flex' />
          {state.currentStep < 3 && (
            <Button
              variant='primary'
              size='md'
              onClick={state.handleNext}
              disabled={
                (state.currentStep === 1 && !state.step1Valid) ||
                (state.currentStep === 2 && !state.step2Valid)
              }
            >
              Next
            </Button>
          )}
          {state.currentStep === 3 && (
            <Button variant='primary' size='md' onClick={state.handleComplete}>
              Complete Setup
            </Button>
          )}
        </Row>
      </Stack>
    </Container>
  );
}
